const pages = [];

for (let i = 1; i <= 50; i++) {
  pages.push({ json: { page: i } });
}

return pages;

const contacts = [];

// Fecha límite: hace 30 días
const now      = new Date();
const limit30  = new Date(now);
limit30.setDate(limit30.getDate() - 30);
const limit30Str = limit30.toISOString().split('T')[0]; // YYYY-MM-DD

for (const item of items) {
  const data = item.json.contacts || [];

  for (const contact of data) {
    const cf   = contact.customFields || [];
    const find = id => cf.find(f => f.id === id)?.value || 0;
    const findStr = id => cf.find(f => f.id === id)?.value || '';

    // Historial de recompras: string con fechas separadas por coma
    const historialRaw   = findStr('wdfNkPf305JjwPdTUBwS');
    const todasFechas    = historialRaw
      ? historialRaw.split(',').map(d => d.trim()).filter(Boolean)
      : [];

    // Contar cuántas están en los últimos 30 días
    const recompras30 = todasFechas.filter(d => d >= limit30Str).length;

    // Última fecha de recompra (campo que se sobreescribe)
    const ultimaRecompra = findStr('4SxhRfKQzstus8dzHsxS');

    contacts.push({
      id:             contact.id,
      fullName:       (contact.firstName + ' ' + (contact.lastName || '')).trim(),
      phone:          contact.phone || '',
      historicPoints: parseInt(find('ciYvzjlWfz9RcmIlqRkO')) || 0,
      redeemedPoints: parseInt(find('jyDAuEv0t1ugBAop1HAQ')) || 0,
      recompras30,
      ultimaRecompra
    });
  }
}

const totalOtorgados  = contacts.reduce((s, c) => s + c.historicPoints, 0);
const totalRedimidos  = contacts.reduce((s, c) => s + c.redeemedPoints, 0);
const tasa = totalOtorgados > 0
  ? parseFloat(((totalRedimidos / totalOtorgados) * 100).toFixed(1))
  : 0;
const totalRecompras30 = contacts.reduce((s, c) => s + c.recompras30, 0);

return [{
  json: {
    totalOtorgados,
    totalRedimidos,
    tasa,
    totalRecompras30,
    contacts
  }
}];
